import axios from 'axios';

const signin = async () =>{
    try{
        const response = await axios.post('/auth/signin',{

        })
    } catch(err){
        if(err.response){
            return err.response.data;
        }

        return {
            success: false,
            message: "서버오류"
        }
    }
}


export default signin;
